                  <input type="text" value={conceptInput} onChange={(e) => setConceptInput(e.target.value)} className="w-full pl-12 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 font-bold transition-all" placeholder="Ej: Paquete Amazon / Pizza" />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Nombre / Comercio</label>
                <div className="relative">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                  <input type="text" value={newNameInput} onChange={(e) => setNewNameInput(e.target.value)} className="w-full pl-12 pr-14 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 font-bold transition-all" placeholder="Ej: El Corte Inglés Elche" />
