                  <div className="relative"><Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} /><input type="tel" value={newPhoneInput} onChange={(e) => setNewPhoneInput(e.target.value)} className="w-full pl-10 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-xs font-medium" placeholder="Teléfono" /></div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Plus Code / Coords / Link</label>
                  <div className="relative"><MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} /><input type="text" value={newCoordsInput} onChange={(e) => setNewCoordsInput(e.target.value)} className="w-full pl-10 pr-4 py-4 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-500 text-xs font-medium" placeholder="Ej: 8C7X+H3 o 38.2,-0.6" /></div>
                </div>
              </div>

              <button type="submit" disabled={isParsing || (!newNameInput.trim() && !newAddressInput.trim() && !newCoordsInput.trim())} className="w-full py-5 bg-blue-600 text-white rounded-[30px] font-black text-lg flex justify-center items-center gap-4 shadow-xl hover:bg-blue-700 active:scale-95 transition-all disabled:opacity-50 uppercase mt-4">
                {isParsing ? (
                  <div className="flex flex-col items-center">
                    <Loader2 className="animate-spin" size={24} />
                    <span className="text-[10px] mt-1 font-bold whitespace-nowrap overflow-hidden text-ellipsis max-w-[150px]">{parsingMessage}</span>
                  </div>
                ) : <Plus size={24} />} 
                Confirmar Parada
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

