import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

// Simple in-memory cache to avoid redundant API calls
const addressCache: Record<string, any> = {};

/**
 * Espera un tiempo determinado para reintentos.
 */
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Envoltorio con reintentos para manejar errores de cuota (429).
 */
async function withRetry<T>(
  fn: () => Promise<T>, 
  onRetry?: (msg: string) => void,
  maxRetries = 4
): Promise<T> {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      lastError = error;
      const isQuotaError = error?.message?.includes("429") || error?.status === 429 || error?.message?.includes("RESOURCE_EXHAUSTED");

      if (isQuotaError && i < maxRetries - 1) {
        const waitTime = Math.pow(2, i) * 3000;
        if (onRetry) onRetry(`Límite de cuota. Reintentando en ${waitTime/1000}s...`);
        await sleep(waitTime);
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

/**
 * Extrae coordenadas de cualquier texto, URL o formato lat,lng.
 */
const extractCoords = (text: string) => {
  if (!text) return null;

  const cleanText = text.trim();
  const latLngMatch = cleanText.match(/^[-+]?([1-8]?\d(\.\d+)?|90(\.0+)?),\s*[-+]?(180(\.0+)?|((1[0-7]\d)|([1-9]?\d))(\.\d+)?)$/);
  if (latLngMatch) {
    const parts = cleanText.split(',');
    return { lat: parseFloat(parts[0]), lng: parseFloat(parts[1]) };
  }

  const patterns = [
    /@(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /query=(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/,
    /!3d(-?\d+\.\d+)!4d(-?\d+\.\d+)/,
    /(-?\d+\.\d+)\s*,\s*(-?\d+\.\d+)/
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) {
      const lat = parseFloat(match[1]);
      const lng = parseFloat(match[2]);
      if (!isNaN(lat) && !isNaN(lng)) return { lat, lng };
    }
  }
  return null;
};

/**
 * Detecta si el string es probablemente un Plus Code
 */
const isPlusCode = (text: string) => {
  return /[A-Z0-9]{4,8}\+[A-Z0-9]{2,}/.test(text);
};

/**
 * Detecta si el string es una URL
 */
const isUrl = (text: string) => {
  return /^https?:\/\//i.test(text.trim());
};

/**
 * Busca un sitio usando Gemini 2.5 (requerido para Maps Grounding).
 */
export const parseAddress = async (
  input: string,
  userLocation?: { latitude: number; longitude: number },
  manualCoords?: string,
  onRetry?: (msg: string) => void
): Promise<{
  recipient: string;
  address: string;
  lat: number;
  lng: number;
  sourceUrl: string;
  phone?: string;
}> => {
  const cacheKey = `${input}|${manualCoords}`.toLowerCase();
  if (addressCache[cacheKey]) {
    return addressCache[cacheKey];
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const rawManual = manualCoords?.trim() || "";

  // 1. Prioridad: Si el manualCoords es una URL de Google Maps, extraemos coordenadas pero preservamos el link
  if (isUrl(rawManual)) {
    const coords = extractCoords(rawManual);
    if (coords) {
      const result = {
        recipient: input || "Punto desde Enlace",
        address: input || "Ubicación mediante URL",
        lat: coords.lat,
        lng: coords.lng,
        sourceUrl: rawManual
      };
      addressCache[cacheKey] = result;
      return result;
    }
  }

  // 2. Intento de extracción local (Coordenadas puras o Plus Code)
  const directCoords = extractCoords(rawManual || input);
  if (directCoords && !isPlusCode(rawManual || input)) {
    const result = {
      recipient: input || "Punto GPS",
      address: input || "Ubicación por coordenadas",
      lat: directCoords.lat,
      lng: directCoords.lng,
      sourceUrl: `https://www.google.com/maps/dir/?api=1&destination=${directCoords.lat},${directCoords.lng}`
    };
    addressCache[cacheKey] = result;
    return result;
  }

  // 3. Si no es directo, usamos Gemini con Grounding
  const anchor = userLocation || { latitude: 38.2622, longitude: -0.6993 };

  const result = await withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Encuentra la ubicación exacta para: "${rawManual || input}". Devuelve el nombre real del sitio, dirección completa y coordenadas exactas.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: anchor.latitude, longitude: anchor.longitude }
          }
        },
      },
    });

    const text = response.text || "";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    let lat: number | null = null;
    let lng: number | null = null;
    let title = "";
    let url = "";

    if (chunks) {
      for (const c of chunks) {
        if (c.maps?.uri) {
          const cData = extractCoords(c.maps.uri);
          if (cData) {
            lat = cData.lat;
            lng = cData.lng;
            url = c.maps.uri;
            title = c.maps.title || title;
          }
        }
      }
    }

    if (!lat || !lng) {
      const fallback = extractCoords(text);
      if (fallback) { lat = fallback.lat; lng = fallback.lng; }
    }

    if (!lat || !lng) throw new Error("No se pudo localizar el punto. Intenta con coordenadas lat,lng o un nombre de sitio más claro.");

    return {
      recipient: title || input,
      address: text.split('\n')[0].substring(0, 100) || input,
      lat,
      lng,
      sourceUrl: url || `https://www.google.com/maps/dir/?api=1&destination=${lat},${lng}`,
      phone: text.match(/(?:\+34|34)?[6789]\d{8}/)?.[0]
    };
  }, onRetry);

  addressCache[cacheKey] = result;
  return result;
};

export const optimizeRoute = async (deliveries: Delivery[], start: string, onRetry?: (msg: string) => void) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Ordena estos IDs de parada para la ruta más corta empezando en ${start}: ${JSON.stringify(deliveries.map(d => ({id: d.id, a: d.address})))}. Responde solo JSON: {"order": ["id1", "id2", ...]}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: { order: { type: Type.ARRAY, items: { type: Type.STRING } } },
          required: ["order"]
        }
      }
    });
    return JSON.parse(response.text).order as string[];
  }, onRetry);
};

