import { GoogleGenAI, Type } from "@google/genai";
import { Delivery } from "../types";

// Simple in-memory cache to avoid redundant API calls
const addressCache: Record<string, any> = {};

/**
 * Espera un tiempo determinado para reintentos.
 */
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Envoltorio con reintentos para manejar errores de cuota (429).
 */
async function withRetry<T>(
  fn: () => Promise<T>, 
  onRetry?: (msg: string) => void,
  maxRetries = 4
): Promise<T> {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      lastError = error;
      const isQuotaError = error?.message?.includes("429") || error?.status === 429 || error?.message?.includes("RESOURCE_EXHAUSTED");

      if (isQuotaError && i < maxRetries - 1) {
        const waitTime = Math.pow(2, i) * 3000;
        if (onRetry) onRetry(`Límite de cuota. Reintentando en ${waitTime/1000}s...`);
        await sleep(waitTime);
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

/**
 * Extrae coordenadas de cualquier texto, URL o formato lat,lng.
 * Soporta decimales con punto (.) o coma (,) común en países hispanohablantes.
 */
const extractCoords = (text: string) => {
  if (!text) return null;

  // Normalizar comas decimales: "38,2805" -> "38.2805"
  let normalized = text.trim().replace(/(\d),(\d)/g, '$1.$2');

  const coordPattern = /([-+]?\d+\.?\d*)\s*[,; \t]\s*([-+]?\d+\.?\d*)/;
  const match = normalized.match(coordPattern);

  if (match) {
    const lat = parseFloat(match[1]);
    const lng = parseFloat(match[2]);

    if (!isNaN(lat) && !isNaN(lng) && 
        lat >= -90 && lat <= 90 && 
        lng >= -180 && lng <= 180) {
      return { lat, lng };
    }
  }

  const urlPatterns = [
    /@(-?\d+\.?\d*)\s*,\s*(-?\d+\.?\d*)/,
    /query=(-?\d+\.?\d*)\s*,\s*(-?\d+\.?\d*)/,
    /!3d(-?\d+\.?\d*)!4d(-?\d+\.?\d*)/
  ];

  for (const pattern of urlPatterns) {
    const urlMatch = normalized.match(pattern);
    if (urlMatch) {
      const lat = parseFloat(urlMatch[1]);
      const lng = parseFloat(urlMatch[2]);
      if (!isNaN(lat) && !isNaN(lng)) return { lat, lng };
    }
  }

  return null;
};

const isPlusCode = (text: string) => {
  return /[A-Z0-9]{4,8}\+[A-Z0-9]{2,}/.test(text);
};

const isUrl = (text: string) => {
  return /^https?:\/\//i.test(text.trim());
};

/**
 * Busca un sitio usando Gemini 2.5 con Maps Grounding afinado para comercios y nombres exactos.
 * Ahora incluye una lógica de búsqueda semántica más profunda para marcas y alias comerciales.
 */
export const parseAddress = async (
  input: string,
  userLocation?: { latitude: number; longitude: number },
  manualCoords?: string,
  onRetry?: (msg: string) => void
): Promise<{
  recipient: string;
  address: string;
  lat: number;
  lng: number;
  sourceUrl: string;
  phone?: string;
}> => {
  const cacheKey = `${input}|${manualCoords}`.toLowerCase();
  if (addressCache[cacheKey]) {
    return addressCache[cacheKey];
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const rawManual = manualCoords?.trim() || "";

  const directCoords = extractCoords(rawManual || input);

  if (isUrl(rawManual) && directCoords) {
    const result = {
      recipient: input || "Punto desde Enlace",
      address: input || "Ubicación mediante URL",
      lat: directCoords.lat,
      lng: directCoords.lng,
      sourceUrl: rawManual
    };
    addressCache[cacheKey] = result;
    return result;
  }

  if (directCoords && !isPlusCode(rawManual || input)) {
    const result = {
      recipient: input || "Punto GPS",
      address: input || `Coordenadas: ${directCoords.lat}, ${directCoords.lng}`,
      lat: directCoords.lat,
      lng: directCoords.lng,
      sourceUrl: `https://www.google.com/maps/dir/?api=1&destination=${directCoords.lat},${directCoords.lng}`
    };
    addressCache[cacheKey] = result;
    return result;
  }

  const anchor = userLocation || { latitude: 38.2622, longitude: -0.6993 };

  const result = await withRetry(async () => {
    // Prompt de búsqueda "Deep Search" para identificar marcas, alias y negocios locales ambiguos
    const prompt = `
      ESTO ES UNA BÚSQUEDA LOGÍSTICA CRÍTICA. 
      Consulta del usuario: "${rawManual || input}".
      Ubicación de referencia del repartidor: Lat: ${anchor.latitude}, Lng: ${anchor.longitude} (Cerca de Elche/Alicante).

      Instrucciones para resolver la ambigüedad:
      1. ANALIZA SEMÁNTICAMENTE: Si el usuario busca una marca (ej: "Paredes", "Pacal Shoes", "Pikolinos"), entiende que se refiere a una tienda, outlet o fábrica de esa marca en el área local.
      2. RESUELVE ALIAS COMERCIALES: Muchos negocios son conocidos por nombres populares que difieren del nombre en Google Maps. Usa tu conocimiento general para mapear "${rawManual || input}" a su entidad comercial real.
      3. BÚSQUEDA GEOGRÁFICA EXPANDIDA: Busca en un radio amplio alrededor de la ubicación del usuario si no hay un resultado exacto inmediato. 
      4. PRIORIDAD COMERCIAL: Elige el establecimiento abierto al público (tienda/oficina) antes que almacenes logísticos, a menos que la consulta sea específica.

      FORMATO DE SALIDA (ESTRICTO):
      Línea 1: NOMBRE COMERCIAL EXACTO (según Google Maps).
      Línea 2: DIRECCIÓN POSTAL COMPLETA.
      Línea 3: Cualquier observación sobre la marca o alias si es relevante.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: { latitude: anchor.latitude, longitude: anchor.longitude }
          }
        },
      },
    });

    const text = response.text || "";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    let lat: number | null = null;
    let lng: number | null = null;
    let title = "";
    let url = "";

    if (chunks && chunks.length > 0) {
      // Intentar encontrar el chunk más relevante. A veces el primero no es el mejor,
      // buscamos uno que tenga título y URI.
      for (const c of chunks) {
        if (c.maps?.uri) {
          const cData = extractCoords(c.maps.uri);
          if (cData) {
            lat = cData.lat;
            lng = cData.lng;
            url = c.maps.uri;
            title = c.maps.title || title;
            // Si el título contiene parte de la búsqueda original, es un match fuerte
            if (input.toLowerCase().split(' ').some(word => title.toLowerCase().includes(word))) {
              break; 
            }
          }
        }
      }
    }

    // Fallback de extracción de texto si fallan los chunks
    if (!lat || !lng) {
      const fallback = extractCoords(text);
      if (fallback) { lat = fallback.lat; lng = fallback.lng; }
    }

    if (!lat || !lng) {
      throw new Error("No pudimos localizar este comercio. Prueba a ser más específico con la calle o la ciudad.");
    }

    const lines = text.split('\n').map(l => l.trim()).filter(l => l.length > 0);

    return {
      recipient: title || lines[0] || input,
      address: lines[1] || lines[0] || input,
      lat,
      lng,
      sourceUrl: url || `https://www.google.com/maps/dir/?api=1&destination=${lat},${lng}`,
      phone: text.match(/(?:\+34|34)?[6789]\d{8}/)?.[0]
    };
  }, onRetry);

  addressCache[cacheKey] = result;
  return result;
};

export const optimizeRoute = async (deliveries: Delivery[], start: string, onRetry?: (msg: string) => void) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Ordena estos IDs de parada para la ruta más corta empezando en ${start}: ${JSON.stringify(deliveries.map(d => ({id: d.id, a: d.address})))}. Responde solo JSON: {"order": ["id1", "id2", ...]}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: { order: { type: Type.ARRAY, items: { type: Type.STRING } } },
          required: ["order"]
        }
      }
    });
    return JSON.parse(response.text).order as string[];
  }, onRetry);
};

