    const statusSteps = [
      "Analizando comercio...",
      "Cruzando datos de marcas...",
      "Localizando en mapa...",
      "Verificando ubicación..."
    ];

    let step = 0;
    const interval = setInterval(() => {
      if (step < statusSteps.length) {
        setParsingMessage(statusSteps[step]);
        step++;
      }
    }, 1500);

    try {
      // Combinamos Nombre y Dirección para que la búsqueda sea mucho más precisa
      const searchQuery = [name, address].filter(Boolean).join(", ");
